    if (IS_ERR(chan)) {
        return PTR_ERR(chan);
    }

    // 准备DMA传输
    desc = dmaengine_prep_memcpy(chan, dst, src, len, 0);
    if (!desc) {
        dma_release_channel(chan);
        return -ENOMEM;
    }

    // 设置回调
    desc->callback = my_dma_callback;
    desc->callback_param = chan;

    // 提交传输
    cookie = dmaengine_submit(desc);
    dma_async_issue_pending(chan);

    return 0;
}
